void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2 = vUv;
if(uv2.x >= 0.5) {uv2.x = 1-uv2.x;}
if(uv2.y >= 0.5) {uv2.y = 1-uv2.y;}

    ret = texture(sampler_main, uv2).xyz;
    //ret = max( ret, texture(sampler_main, 1-vUv).zyx );

    float L = lum(ret);
    float use_tex = 0.75 - clamp01(L*3-1);
    vec3 tex= texture(sampler_jakarta_city,vUv).xyz;

    tex*= tex;
      // shadow:
      float L2 = lum(GetBlur2(vUv - 0.01));

    ret = mix(ret, tex, use_tex);

    ret *= 0.90; //old gamma effect


  fragColor = ret;
}
